      "mainEntity": [
        {
          "@type": "Question",
          "name": "How are market and non-market vesting conditions treated under Ind AS 102?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Market conditions such as a share price target are built into the grant date fair value and are never reversed, even if the target is missed. Service and non-market performance conditions are excluded from fair value; instead the number of options expected to vest is revised each period. If 100 of 500 options lapse, the cumulative charge is trued down."
          }
        },
        {
          "@type": "Question",
          "name": "What is the difference between an equity-settled and a cash-settled share-based payment?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "An equity settled award is measured once at grant date fair value and credited to a share options outstanding account, while a cash settled award such as a phantom stock or stock appreciation right is a liability remeasured at fair value on every reporting date until settlement. Cash settled plans therefore keep hitting profit as the share price moves."
          }
        },
        {
          "@type": "Question",
          "name": "Do companies following AS instead of Ind AS have to expense ESOPs?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Yes. The ICAI Guidance Note on Accounting for Share-based Payments requires fair value based accounting, and the intrinsic value alternative was withdrawn for grants made on or after 1 April 2021. A company on AS therefore books the same kind of employee benefit expense as an Ind AS 102 filer, credited to a share options outstanding reserve."
          }
        }
      ]
